const fs = require('fs');
const path = require('path');
const { execFileSync } = require('child_process');

const params = $('Set Global Parameters').first().json;
const testCardFilter = (params.TestCardFilter || '').trim();

const raw = $input.first().json;
const deck = raw.data !== undefined ? raw.data : raw;

const deckDir = ((deck.Assets && deck.Assets.Directory)
  ? deck.Assets.Directory
  : 'D:/data/cards/Standard').replace(/\\+/g, '/').replace(/\//g, path.sep);

const cardRefs = deck.Cards;
if (!cardRefs || cardRefs.length === 0) {
  throw new Error('[Generate Reversed CardImageUpright] No Cards found in Deck.json.');
}

const filteredCards = testCardFilter
  ? cardRefs.filter(c => c.Card === testCardFilter)
  : cardRefs;

if (filteredCards.length === 0) {
  throw new Error('[Generate Reversed CardImageUpright] No cards matched filter: ' + JSON.stringify(testCardFilter));
}

const results = { processed: 0, skipped: 0, failed: 0, cards: [] };

for (const cardRef of filteredCards) {
  const cardName = cardRef.Card;
  const cardFilePath = path.join(deckDir, cardRef.File.replace(/\//g, path.sep));

  // Read card JSON
  let cardRaw;
  try {
    cardRaw = JSON.parse(fs.readFileSync(cardFilePath, 'utf8').replace(/^\uFEFF/, ''));
  } catch (e) {
    console.warn('[Generate Reversed CardImageUpright] Cannot read card: ' + cardName + ': ' + e.message);
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'Cannot read card file: ' + e.message });
    continue;
  }

  const card = cardRaw['data.Cards'] || cardRaw;
  const cardDir = (card.Directory || path.join(deckDir, 'Cards')).replace(/\\+/g, '/').replace(/\//g, path.sep);

  // Find reversed record
  const reversedRecord = (card.records || []).find(r => r.Orientation === 'reversed');
  if (!reversedRecord) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No reversed record' });
    continue;
  }

  // Get the reversed record's CardImage as source
  const sourceImageName = reversedRecord.Assets && reversedRecord.Assets.CardImage;
  if (!sourceImageName) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No reversed Assets.CardImage' });
    continue;
  }

  const sourceImagePath = path.join(cardDir, sourceImageName);
  if (!fs.existsSync(sourceImagePath)) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'Reversed CardImage not found: ' + sourceImagePath });
    continue;
  }

  // Determine output filename from CardImageUpright field, or generate one
  const slug = cardName.replace(/[()]/g, '').replace(/\s+/g, '_');
  const outputName = (reversedRecord.Assets && reversedRecord.Assets.CardImageUpright)
    ? reversedRecord.Assets.CardImageUpright
    : 'CARDIMGUPRIGHT_' + slug + '_reversed.png';
  const outputPath = path.join(cardDir, outputName);

  // Skip if output already exists (insertable/overridable convention)
  if (fs.existsSync(outputPath)) {
    // Still ensure the JSON field is set
    if (!reversedRecord.Assets) reversedRecord.Assets = {};
    if (reversedRecord.Assets.CardImageUpright !== outputName) {
      reversedRecord.Assets.CardImageUpright = outputName;
      fs.writeFileSync(cardFilePath, JSON.stringify(cardRaw, null, 2), 'utf8');
    }
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'Already exists' });
    continue;
  }

  // Rotate reversed CardImage by 180 degrees using ffmpeg
  try {
    execFileSync('ffmpeg', [
      '-y',
      '-i', sourceImagePath,
      '-vf', 'rotate=PI',
      outputPath
    ], { encoding: 'utf8', stdio: 'pipe' });
  } catch (e) {
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'ffmpeg rotate error: ' + (e.stderr || e.message) });
    continue;
  }

  // Verify output was created
  if (!fs.existsSync(outputPath)) {
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'ffmpeg produced no output file' });
    continue;
  }

  // Update card JSON with CardImageUpright field if not already set
  if (!reversedRecord.Assets) reversedRecord.Assets = {};
  if (reversedRecord.Assets.CardImageUpright !== outputName) {
    reversedRecord.Assets.CardImageUpright = outputName;
    fs.writeFileSync(cardFilePath, JSON.stringify(cardRaw, null, 2), 'utf8');
  }

  results.processed++;
  results.cards.push({
    card: cardName,
    status: 'generated',
    source: sourceImageName,
    output: outputName
  });
}

if (results.processed === 0 && results.failed === 0 && results.skipped === 0) {
  throw new Error('[Generate Reversed CardImageUpright] No cards processed. Check TestCardFilter and Deck.json Cards array.');
}

return [{ json: results }];
